{let t=window.location.origin;if(e!=="detail"){lr(null);let r=document.getElementById("schema-housing-detail");r&&r.remove()}if(e==="create")_e("S\xE6lg andelsbolig selv \u2013 100% gratis | Salg & Bytte","S\xE6lg din andelsbolig selv og spar m\xE6gleren. Det er 100% gratis at oprette din annonce til salg eller bytte af andelsbolig.",`${t}/saelg-andelsbolig`);else if(e==="sell_landing")_e("S\xE6lg din andelsbolig selv \u2013 100% gratis | Salg & Bytte","St\xE5r du overfor et salg eller bytte af din andelsbolig? Lad roomies hj\xE6lpe dig trygt og nemt videre. Uanset om din bolig ligger i K\xF8benhavn, Aarhus, p\xE5 Frederiksberg, Amager, \xD8sterbro eller et andet sted i Danmark, g\xF8r vi det enkelt at finde den rette k\xF8ber.",`${t}/saelg-andelsbolig-selv-koncept`),lr({"@context":"https://schema.org","@type":"FAQPage",mainEntity:[{"@type":"Question",name:"M\xE5 jeg s\xE6lge min andelsbolig selv?",acceptedAnswer:{"@type":"Answer",text:"Ja, du m\xE5 i h\xF8j grad gerne s\xE6lge din andelsbolig selv. Faktisk er selvsalg den mest almindelige m\xE5de at s\xE6lge andelsboliger p\xE5 i Danmark. Du beh\xF8ver ingen ejendomsm\xE6gler, da andelsboligforeningens administrator typisk st\xE5r for at udarbejde overdragelsesaftalen og h\xE5ndtere det juridiske papirarbejde."}},{"@type":"Question",name:"Hvad er processen n\xE5r jeg s\xE6lger selv?",acceptedAnswer:{"@type":"Answer",text:"Processen er simpel: 1. Unders\xF8g f\xF8rst, hvilke regler og processer der g\xE6lder i din specifikke andelsboligforening (f.eks. krav til vurderingsmand). 2. Opret en gratis annonce p\xE5 roomies og fremvis boligen for interesserede k\xF8bere. 3. N\xE5r du har fundet din k\xF8ber, giver du besked til foreningens administrator, som herefter opretter overdragelsesaftalen og indhenter bestyrelsens godkendelse."}},{"@type":"Question",name:"Er det usikkert at s\xE6lge uden en ejendomsm\xE6gler?",acceptedAnswer:{"@type":"Answer",text:"Nej, og salg g\xE5r ofte hurtigere ved selvsalg. Alt salg af andelsboliger skal lovpligtigt godkendes af andelsboligforeningens bestyrelse. Det er foreningens professionelle administrator (ofte en advokat), der udarbejder selve k\xF8bsaftalen og h\xE5ndterer k\xF8besummen sikkert via en deponeringskonto. M\xE6glerens prim\xE6re job er blot at finde k\xF8beren, hvilket vi hj\xE6lper dig med."}},{"@type":"Question",name:"Hvad koster det at s\xE6lge andelsbolig?",acceptedAnswer:{"@type":"Answer",text:"Hos roomies er det 100% gratis at s\xE6lge. Dine eneste udgifter ved et selvsalg vil typisk v\xE6re et overdragelsesgebyr til foreningens administrator, udgiften til en vurderingsmand, et gebyr til banken for indfrielse af dit eventuelle l\xE5n, samt et el- og VVS-tjek, hvis din forening kr\xE6ver det."}}]});else if(e==="faq")_e("Ofte stillede sp\xF8rgsm\xE5l | roomies","F\xE5 svar p\xE5 alle dine sp\xF8rgsm\xE5l om k\xF8b, salg og bytte af andelsboliger og l\xE6s mere om hvordan roomies fungerer her.",`${t}/faq`),lr({"@context":"https://schema.org","@type":"FAQPage",mainEntity:[{"@type":"Question",name:"Hvordan fungerer konceptet?",acceptedAnswer:{"@type":"Answer",text:"I dag er andelsboligmarkedet spredt ud over hele internettet \u2013 p\xE5 DBA, Boliga, i over 50 forskellige Facebook-grupper og mange andre steder. Det problem l\xF8ser vi. Vi samler markedet \xE9t sted og g\xF8r det skjulte marked synligt for alle. Det er 100% gratis at s\xE6lge eller bytte din andelsbolig via os, og vi s\xF8rger for at annoncere din bolig ud til mange tusinde k\xF8bere."}},{"@type":"Question",name:"Koster det penge at s\xE6lge min andelsbolig?",acceptedAnswer:{"@type":"Answer",text:"Nej, det er 100% gratis at oprette en salgs- eller bytteannonce p\xE5 roomies. Vi har fjernet de dyre mellemled, s\xE5 du trygt kan finde den rette k\xF8ber uden at skulle have penge op af lommen."}},{"@type":"Question",name:"Hvad koster det at kontakte en s\xE6lger?",acceptedAnswer:{"@type":"Answer",text:"For kun 99 kr. om m\xE5neden f\xE5r du fuld adgang til at kontakte alle s\xE6lgere direkte og se de fulde adressedetaljer. Der er 0 skjulte gebyrer og absolut ingen binding \u2013 du kan afmelde dig pr\xE6cis, n\xE5r du vil. Vores pris er desuden over 75% billigere end lignende portaler."}},{"@type":"Question",name:"Hvad er processen n\xE5r jeg s\xE6lger selv?",acceptedAnswer:{"@type":"Answer",text:"Overordnet set er processen simpel: 1. Unders\xF8g f\xF8rst, hvilke regler og processer der g\xE6lder i din specifikke andelsboligforening (f.eks. krav til vurderingsmand). 2. Opret en gratis annonce p\xE5 roomies. Vi finder interesserede k\xF8bere og du fremviser boligen. 3. N\xE5r du har fundet din k\xF8ber, giver du besked til foreningens administrator, som herefter opretter overdragelsesaftalen og indhenter bestyrelsens godkendelse."}},{"@type":"Question",name:"Hvordan fungerer BoligMatch?",acceptedAnswer:{"@type":"Answer",text:"Med BoligMatch overv\xE5ger vi markedet for dig helt automatisk. Du opretter dine kriterier (f.eks. pris, st\xF8rrelse og omr\xE5de), og vi sender dig en e-mail i samme sekund, som en andelsbolig, der matcher dine dr\xF8mme, bliver sat til salg."}},{"@type":"Question",name:"Hvor kommer boligerne fra?",acceptedAnswer:{"@type":"Answer",text:"Boligerne p\xE5 platformen kommer fra to prim\xE6re kilder. Flere og flere andelshavere opretter selv deres salgs- og bytteannoncer direkte hos os, fordi det er gratis, og fordi vi hj\xE6lper med salget. For at hj\xE6lpe dig med at overv\xE5ge et ellers uoverskueligt marked, bruger vi derudover avanceret teknologi til automatisk at indsamle annoncer fra resten af internettet, herunder DBA, Boliga og diverse internetsider. P\xE5 den m\xE5de beh\xF8ver du kun at lede \xE9t sted. Vi h\xE5ber du finder dr\xF8mmeboligen hos os \u{1F60A}"}}]});else if(e==="soeg_vaerelse")_e("S\xF8g v\xE6relse og find din n\xE6ste roomie | roomies","Find ledige v\xE6relser i K\xF8benhavn, Aarhus og resten af Danmark. Filtr\xE9r efter pris, st\xF8rrelse og den hverdag, du gerne vil v\xE6re en del af.",`${t}/soeg-vaerelse`);else if(e!=="room_detail")if(e==="housing_list")_e("Andelsboliger til salg i K\xF8benhavn, Aarhus og hele Danmark","Se alle aktuelle andelsboliger til salg her. Find din nye andelslejlighed i K\xF8benhavn (inkl. 2100 \xD8sterbro), Amager, Frederiksberg, Aarhus. m.m.",`${t}/liste`);else if(e==="housing_map")_e("Kort over andelsboliger til salg | Find andelsbolig n\xE6r dig","S\xF8g efter andelsboliger til salg via vores kort. Find nemt en andelsbolig i indre K\xF8benhavn, Amager, Frederiksberg, Lyngby, Aarhus og resten af landet.",`${t}/kort`);else if(e==="terms_and_conditions")_e("Vilk\xE5r og Betingelser | roomies","L\xE6s de g\xE6ldende vilk\xE5r og betingelser for brug af roomies. F\xE5 overblik over betingelser for annoncering, abonnement og persondatah\xE5ndtering.",`${t}/vilkaar`);else if(e==="conversations")_e("Beskeder | roomies","Se og svar p\xE5 dine samtaler med s\xE6lgere p\xE5 roomies.",`${t}/beskeder`);else if(e==="about_us")_e("Om roomies | Nem, billig og hurtig bolighandel","L\xE6s historien bag roomies. Vi tilstr\xE6ber at g\xF8re det mere gennemsigtigt, billigt og nemt at k\xF8be, s\xE6lge og bytte andelsboliger i Danmark.",`${t}/om-os`);else if(e==="agent"||e==="agent_create"||e==="agent_edit")_e("RoomieAgent | F\xE5 besked om nye v\xE6relser","Opret en gratis RoomieAgent og f\xE5 besked, n\xE5r et v\xE6relse matcher dit budget og dine omr\xE5der.",`${t}/boligovervaagning`);else if(e==="blog"){let r=Ei(Ea.get("slug"));r?(_e(`${r.title} | roomies`,r.excerpt,`${t}${ir(r)}`),lr(aa(r,t))):(_e("Blog | roomies","L\xE6s historier, tips og erfaringer fra andelsboligmarkedet. F\xE5 inspiration til boligjagten, selvsalg og BoligMatch.",`${t}/blog`),lr(sa(t)))}else e==="detail"||_e("Andelsboliger til salg | K\xF8b, Salg & Bytte af andelsbolig","Danmarks nye portal for andelsboliger. Find andelsboliger til salg i K\xF8benhavn, Frederiksberg og Aarhus, eller s\xE6lg din andelsbolig selv \u2013 100% gratis.",t)}var Ai=Object.fromEntr